test_that("ci_tree_control_grid creates greedy controls only", {
  grid <- ci_tree_control_grid(
    minsplit = c(4, 6),
    minbucket = 2,
    minprob = c(0, 0.1),
    maxdepth = 1:2,
    min_gain = c(0, 0.01),
    mtry = c(1, 2),
    ntree = c(5, 10)
  )

  expect_s3_class(grid, "data.table")
  expect_equal(nrow(grid), 64L)
  expect_true(all(c(
    "minsplit", "minbucket", "minprob", "maxdepth", "min_gain", "mtry",
    "ntree"
  ) %in% names(grid)))
  expect_false("mincriterion" %in% names(grid))
})

test_that("ci_cv_folds creates reproducible folds", {
  folds_a <- ci_cv_folds(12, v = 3, seed = 99)
  folds_b <- ci_cv_folds(12, v = 3, seed = 99)

  expect_equal(folds_a, folds_b)
  expect_equal(sort(unique(folds_a)), 1:3)
  expect_equal(length(folds_a), 12L)
})

test_that("ci_cv_folds validates input", {
  expect_error(ci_cv_folds(3, v = 4), "`v` cannot exceed `n`")
  expect_error(ci_cv_folds(5, strata = 1:4), "`strata` must have length `n`")
})

test_that("predict_ctree_ci_terminal_mean returns one prediction per row", {
  toy_data <- data.frame(
    rank = c(10, 20, 30, 40, 50, 60),
    outcome = c(1, 0, 1, 0, 1, 1),
    income = c(2, 4, 6, 8, 10, 12)
  )
  fit <- ctree_ci(
    cbind(rank, outcome) ~ income,
    data = toy_data,
    rank_name = "rank",
    outcome_name = "outcome",
    control = ci_tree_control(minsplit = 1, minbucket = 1, maxdepth = 1)
  )

  pred <- predict_ctree_ci_terminal_mean(fit, toy_data, outcome_name = "outcome")

  expect_type(pred, "double")
  expect_equal(length(pred), nrow(toy_data))
  expect_true(all(pred >= 0 & pred <= 1))
})

