test_that("ci prediction metrics score simple binary predictions", {
  truth <- c(0, 1, 1, 0)
  estimate <- c(0.1, 0.8, 0.7, 0.2)

  expect_lt(ci_brier_score(truth, estimate), 0.1)
  expect_lt(ci_log_loss(truth, estimate), 0.4)
  expect_equal(ci_roc_auc(truth, estimate), 1)

  out <- ci_prediction_metrics(truth, estimate)
  expect_s3_class(out, "data.table")
  expect_true(all(c("brier", "log_loss", "roc_auc") %in% names(out)))
})

test_that("tune_ctree_ci selects greedy tree controls and CI type", {
  toy_data <- data.frame(
    rank = c(10, 20, 30, 40, 50, 60, 70, 80),
    outcome = c(1, 0, 1, 0, 1, 1, 0, 1),
    income = c(2, 4, 6, 8, 10, 12, 14, 16),
    group = factor(c("a", "a", "b", "b", "a", "a", "b", "b"))
  )
  grid <- ci_tree_control_grid(
    minsplit = 1,
    minbucket = 1,
    minprob = 0,
    maxdepth = 1:2
  )

  tuned <- tune_ctree_ci(
    cbind(rank, outcome) ~ income + group,
    data = toy_data,
    rank_name = "rank",
    outcome_name = "outcome",
    type = c("CI", "CIg"),
    control_grid = grid,
    v = 2,
    seed = 1,
    refit = TRUE
  )

  expect_s3_class(tuned, "ci_tree_tuning")
  expect_s3_class(tuned$fold_results, "data.table")
  expect_s3_class(tuned$summary, "data.table")
  expect_equal(nrow(tuned$fold_results), nrow(grid) * 2L * 2L)
  expect_s3_class(tuned$best_fit, "ci_tree")
  expect_true(tuned$best_type %in% c("CI", "CIg"))
  expect_true("type" %in% names(tuned$best_params))
  expect_false("mincriterion" %in% names(tuned$best_params))
})

test_that("tune_ctree_ci can minimize Brier score", {
